import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { Button, Pagination, StatusBadge, addToast } from '@linm-soft/common-components';
import { useAppDispatch } from '../../../store/hooks';
import { bhService } from '../../../services/bh/bhService';
import type { SalesReturnDto } from '../../../services/bh/models';
import styles from '../../../styles/erpPage.module.css';

const PAGE_SIZE = 20;

const TraHangBanListPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const navigate = useNavigate();
  const [page, setPage] = useState(1);
  const [items, setItems] = useState<SalesReturnDto[]>([]);
  const [totalCount, setTotalCount] = useState(0);
  const [loading, setLoading] = useState(false);

  React.useEffect(() => {
    let cancelled = false;
    setLoading(true);
    const t = setTimeout(() => {
      bhService.getSalesReturns({ page, pageSize: PAGE_SIZE })
        .then(res => { if (!cancelled) { setItems(res.items); setTotalCount(res.totalCount); } })
        .catch(() => { if (!cancelled) { setItems([]); setTotalCount(0); } })
        .finally(() => { if (!cancelled) setLoading(false); });
    }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, [page]);

  return (
    <div className={styles.page}>
      <div className={styles.pageHeader}>
        <h1 className={styles.title}>Trả hàng bán</h1>
        <Button variant="primary" onClick={() => navigate('/bh/tra-hang/them')}>Tạo phiếu trả</Button>
      </div>
      <div className={styles.tableCard}>
        {loading ? <div className={styles.loading}>Đang tải...</div> : items.length === 0 ? (
          <div className={styles.empty}><p>Chưa có phiếu trả (API sales-returns có thể chưa implement)</p></div>
        ) : (
          <table className={styles.table}>
            <thead><tr><th>Số phiếu</th><th>Khách hàng</th><th>TT</th></tr></thead>
            <tbody>{items.map(r => (
              <tr key={r.id}><td><button type="button" className={styles.codeLink} onClick={() => navigate(`/bh/tra-hang/${r.id}`)}>{r.code}</button></td>
              <td>{r.customerName ?? '—'}</td><td><StatusBadge status={r.status ?? 'Draft'} /></td></tr>
            ))}</tbody>
          </table>
        )}
        {totalCount > 0 && <Pagination currentPage={page} totalPages={Math.ceil(totalCount / PAGE_SIZE)} totalCount={totalCount} pageSize={PAGE_SIZE} onPageChange={setPage} />}
      </div>
    </div>
  );
};
export default TraHangBanListPage;
